using UnityEngine;
using System.Collections;

public class ScreenShake : MonoBehaviour
{
    public static ScreenShake Instance;

    private Transform cameraTransform;
    private Vector3 originalPosition;

    private float shakeDuration = 0f;
    private float shakeMagnitude = 0.1f;
    private float shakeSpeed = 1f;

    void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
        }
        else
        {
            Destroy(gameObject);
        }
    }

    void Start()
    {
        cameraTransform = Camera.main.transform;
        originalPosition = cameraTransform.position;
    }

    void Update()
    {
        if (shakeDuration > 0)
        {
            // Perlin noise based shake
            float x = Mathf.PerlinNoise(Time.time * shakeSpeed, 0) * 2 - 1;
            float y = Mathf.PerlinNoise(0, Time.time * shakeSpeed) * 2 - 1;

            Vector3 shakeOffset = new Vector3(x, y, 0) * shakeMagnitude;
            cameraTransform.position = originalPosition + shakeOffset;

            shakeDuration -= Time.deltaTime;

            // Smoothly reduce shake
            float progress = shakeDuration / 0.5f;
            shakeMagnitude *= progress;
        }
        else
        {
            // Reset camera
            if (cameraTransform.position != originalPosition)
            {
                cameraTransform.position = originalPosition;
            }
        }
    }

    public void Shake(float duration, float magnitude)
    {
        shakeDuration = duration;
        shakeMagnitude = magnitude;
        shakeSpeed = 20f;

        // Store original position
        originalPosition = cameraTransform.position;

        Debug.Log("Screen shake: duration=" + duration + ", magnitude=" + magnitude);
    }

    public void Shake(float duration, float magnitude, float speed)
    {
        shakeDuration = duration;
        shakeMagnitude = magnitude;
        shakeSpeed = speed;

        originalPosition = cameraTransform.position;
    }

    // Example: Shake on hit
    public void OnPlayerHit()
    {
        Shake(0.3f, 0.1f);
    }

    // Example: Shake on explosion
    public void OnExplosion()
    {
        Shake(0.5f, 0.3f, 30f);
    }

    // Example: Shake on death
    public void OnPlayerDeath()
    {
        Shake(1f, 0.2f);
    }
}

